[asy]
unitsize(0.4 cm);

pair A, B, C, D, P;

A = (4,12);
B = (0,0);
C = (14,0);
D = (B + C)/2;
P = (A + reflect(B,C)*(A))/2;

draw(A--B--C--cycle);
draw(A--D);
draw(A--P);

label("$A$", A, dir(90));
label("$B$", B, SW);
label("$C$", C, SE);
label("$D$", D, SE);
label("$P$", P, SW);

